// ═══════════════════════════════════════════
// مدیریت وضعیت
// ═══════════════════════════════════════════
const STORAGE_KEY = "psych_quiz_v3";
function loadState() {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY)) || {}; }
  catch(e) { return {}; }
}
function saveState(s) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(s)); }
  catch(e) {}
}

let currentQList = [];
let state = {};
const app = document.getElementById("appContainer");

// helper: انیمیشن ورود صفحه
function animatePage() {
  app.classList.remove('page-enter');
  void app.offsetWidth; // reflow
  app.classList.add('page-enter');
}

// helper: ثبت حالت برای دکمه برگشت
function setMode(mode) {
  window.__currentMode = mode;
  history.pushState({ page: mode }, '');
}

// ═══════════════════════════════════════════
// صفحه اصلی
// ═══════════════════════════════════════════
function renderHome() {
  setMode('home');
  animatePage();
  const s = loadState();
  const res = s.results || {};

  let savedHtml = '';
  if (s.mode === 'quiz' && typeof s.qIndex === 'number' && s.qIndex > 0) {
    const catLabel = s.catId === 'all' ? 'همه سوالات'
      : s.catId === 'pre' ? 'قبل از ۱۴۰۰'
      : s.catId === 'post' ? '۱۴۰۰ به بعد'
      : (CATEGORIES.find(c => c.id === s.catId) || {name:'...'}).name;
    savedHtml = `
      <div class="saved-badge">📌 ادامه از: <b>${catLabel}</b> — سوال ${s.qIndex + 1}</div>
      <button class="btn" onclick="continueSaved()">← ادامه جلسه قبل</button>`;
  }

  const catCards = CATEGORIES.map(cat => {
    const catQs = questions.filter(q => q.cat === cat.id);
    const done = catQs.filter((_, i) => res[cat.id + '_' + i] !== undefined).length;
    const correct = catQs.filter((_, i) => res[cat.id + '_' + i] === true).length;
    const prog = done > 0 ? `✅ ${correct}/${done}` : '';
    return `<div class="cat-card" onclick="startMode('${cat.id}')">
      <div class="cat-icon">${cat.icon}</div>
      <div class="cat-name">${cat.name}</div>
      <div class="cat-count">${catQs.length} سوال</div>
      <div class="cat-progress">${prog}</div>
    </div>`;
  }).join('');

  const totalDone = Object.keys(res).length;
  const totalCorrect = Object.values(res).filter(v => v === true).length;
  const totalPct = totalDone > 0 ? Math.round((totalCorrect / totalDone) * 100) : 0;

  app.innerHTML = `
    <div class="header">🧠 کنکور ارشد روانشناسی</div>
    ${savedHtml}
    <div class="mini-stats">
      <div class="mini-stat"><div class="val">${questions.length}</div><div class="lbl">کل سوال</div></div>
      <div class="mini-stat"><div class="val">${totalDone}</div><div class="lbl">پاسخ داده</div></div>
      <div class="mini-stat"><div class="val">${totalCorrect}</div><div class="lbl">صحیح</div></div>
      <div class="mini-stat"><div class="val">${totalPct}٪</div><div class="lbl">درصد</div></div>
    </div>
    <div class="cat-card all-mode" onclick="startMode('all')">
      <div class="cat-icon">📋</div>
      <div class="cat-name">همه سوالات (${questions.length} سوال)</div>
    </div>
    <div class="cat-grid">${catCards}</div>
    <div style="display:flex;gap:10px">
      <button class="btn warn" onclick="startMode('pre')">📜 کلاسیک (${questions.filter(q=>q.era==='pre').length})</button>
      <button class="btn info" onclick="startMode('post')">🆕 ۱۴۰۰+ (${questions.filter(q=>q.era==='post').length})</button>
    </div>
    <hr class="divider">
    <div style="display:flex;gap:10px">
      <button class="btn secondary" onclick="renderAbout()">ℹ️ درباره اپ</button>
      <button class="btn dark" onclick="confirmReset()">🗑 پاک کردن پیشرفت</button>
    </div>`;
}

function continueSaved() {
  const s = loadState();
  if (!s.catId) return;
  buildQList(s.catId);
  state = s;
  renderQuestion();
}

function buildQList(catId) {
  if (catId === 'all')  currentQList = [...questions];
  else if (catId === 'pre')  currentQList = questions.filter(q => q.era === 'pre');
  else if (catId === 'post') currentQList = questions.filter(q => q.era === 'post');
  else currentQList = questions.filter(q => q.cat === catId);
}

function startMode(catId) {
  buildQList(catId);
  const s = loadState();
  state = { mode:'quiz', catId, qIndex:0, score:0, answered:false, results: s.results || {} };
  saveState(state);
  renderQuestion();
}

function confirmReset() {
  if (confirm('آیا مطمئن هستید؟\nتمام پیشرفت پاک می‌شود.')) {
    localStorage.removeItem(STORAGE_KEY);
    state = {};
    renderHome();
  }
}

// ═══════════════════════════════════════════
// صفحه سوال
// ═══════════════════════════════════════════
function renderQuestion() {
  setMode('quiz');
  animatePage();
  state = loadState();
  const qi = state.qIndex || 0;
  if (qi >= currentQList.length) { renderResult(); return; }

  const q = currentQList[qi];
  const total = currentQList.length;
  const pct = Math.round((qi / total) * 100);
  const catInfo = CATEGORIES.find(c => c.id === q.cat) || {name:'', icon:''};
  const eraBadge = q.era === 'pre'
    ? `<span class="era-badge era-before">📜 کلاسیک</span>`
    : `<span class="era-badge era-after">🆕 ۱۴۰۰+</span>`;

  const letters = ['الف','ب','پ','ت'];
  const optHtml = q.o.map((opt, i) =>
    `<button class="option-btn" id="opt${i}" onclick="answer(${i})">${letters[i]}. ${opt}</button>`
  ).join('');

  app.innerHTML = `
    <div class="header">🧠 روانشناسی کنکور ارشد</div>
    <div class="progress-text">سوال ${qi+1} از ${total} &nbsp;|&nbsp; امتیاز: ${state.score||0}</div>
    <div class="progress-bar-wrap">
      <div class="progress-bar-fill" style="width:${pct}%"></div>
    </div>
    <div class="question-box">
      <div style="margin-bottom:6px">${eraBadge}<span class="category-badge">${catInfo.icon} ${catInfo.name}</span></div>
      ${q.q}
    </div>
    <div class="options">${optHtml}</div>
    <div id="feedbackBox" class="feedback hidden"></div>
    <div class="action-row hidden" id="actionRow">
      <button class="btn" onclick="nextQ()">سوال بعدی ←</button>
      <button class="btn secondary" onclick="renderHome()">🏠 خانه</button>
    </div>`;
}

function answer(idx) {
  const s = loadState();
  if (s.answered) return;

  const q = currentQList[s.qIndex || 0];
  const isCorrect = idx === q.c;

  s.answered = true;
  if (isCorrect) s.score = (s.score || 0) + 1;
  const rKey = s.catId + '_' + s.qIndex;
  if (!s.results) s.results = {};
  s.results[rKey] = isCorrect;
  saveState(s);
  state = s;

  document.querySelectorAll('.option-btn').forEach((b, i) => {
    b.classList.add('disabled');
    if (i === q.c) b.classList.add('correct');
    else if (i === idx && !isCorrect) b.classList.add('incorrect');
  });

  const fb = document.getElementById('feedbackBox');
  if (fb) {
    fb.classList.remove('hidden');
    fb.innerHTML = isCorrect
      ? `✅ <b>درست!</b> 💡 ${q.ex}`
      : `❌ <b>اشتباه!</b> پاسخ صحیح: <b>${['الف','ب','پ','ت'][q.c]}. ${q.o[q.c]}</b><br>💡 ${q.ex}`;
  }
  const ar = document.getElementById('actionRow');
  if (ar) ar.classList.remove('hidden');
}

function nextQ() {
  let s = loadState();
  s.qIndex = (s.qIndex || 0) + 1;
  s.answered = false;
  saveState(s);
  state = s;
  if (s.qIndex >= currentQList.length) renderResult();
  else renderQuestion();
}

// ═══════════════════════════════════════════
// صفحه نتیجه
// ═══════════════════════════════════════════
function renderResult() {
  setMode('result');
  animatePage();
  const s = loadState();
  const total = currentQList.length;
  const score = s.score || 0;
  const pct = Math.round((score / total) * 100);
  const stars = pct >= 80 ? '⭐⭐⭐' : pct >= 60 ? '⭐⭐' : '⭐';
  const msg = pct >= 80 ? '🎉 عالی! آفرین!' : pct >= 60 ? '👍 خوب بود، ادامه بده!' : '📖 نیاز به مطالعه بیشتر داری.';

  app.innerHTML = `
    <div class="header">🧠 نتیجه آزمون</div>
    <div class="result-screen page-enter">
      <div style="font-size:2rem">${stars}</div>
      <div style="margin-top:8px;font-size:1.1rem">${msg}</div>
      <div class="score">${score} / ${total}</div>
      <div class="score-detail">درصد صحیح: ${pct}٪</div>
    </div>
    <div class="action-row">
      <button class="btn" onclick="startMode('${s.catId}')">🔄 تکرار</button>
      <button class="btn dark" onclick="renderHome()">🏠 خانه</button>
    </div>`;

  s.qIndex = 0; s.score = 0; s.answered = false; s.mode = 'result';
  saveState(s);
}

// ═══════════════════════════════════════════
// صفحه درباره ما + هشدار علمی
// ═══════════════════════════════════════════
function renderAbout() {
  setMode('about');
  animatePage();
  app.innerHTML = `
    <div class="header">ℹ️ درباره اپلیکیشن</div>
    <div class="about-box">
      <p><b>🧠 کنکور ارشد روانشناسی</b></p>
      <br>
      <p>این اپلیکیشن شامل <b>${questions.length} سوال پرتکرار</b> کنکور ارشد روانشناسی است که در ۸ دسته موضوعی دسته‌بندی شده‌اند:</p>
      <br>
      <p>📚 تاریخچه و مکاتب &nbsp;|&nbsp; 🌱 رشد و تکامل</p>
      <p>🧠 روانشناسی بالینی &nbsp;|&nbsp; 🔬 زیست‌شناختی</p>
      <p>💡 یادگیری و حافظه &nbsp;|&nbsp; 👥 اجتماعی و شخصیت</p>
      <p>📊 روش تحقیق و آمار &nbsp;|&nbsp; 💬 روان‌درمانی</p>
      <br>
      <p>✅ کار بدون اینترنت &nbsp;|&nbsp; ✅ ذخیره پیشرفت</p>
      <br>
      <p style="font-size:0.8rem;color:#888">نسخه ۱.۰ — ساخته شده با ❤️ برای داوطلبان کنکور ارشد</p>
    </div>
    <div class="disclaimer-box">
      ⚠️ <b>هشدار مهم:</b> سوالات این اپلیکیشن جنبه آموزشی دارند و بر اساس منابع پرتکرار کنکور ارشد تهیه شده‌اند. این اپ جایگزین منابع درسی اصلی و مشاوره اساتید نمی‌شود. برای موفقیت در کنکور، حتماً از منابع معتبر و کلاس‌های آموزشی استفاده کنید.
    </div>
    <button class="btn dark" onclick="renderHome()">← بازگشت به خانه</button>`;
}

// ═══════════════════════════════════════════
// شروع اپ
// ═══════════════════════════════════════════
renderHome();
